import { GoogleGenAI, HarmCategory, HarmBlockThreshold } from "@google/genai";

// Fail-fast behavior: Check for API key on module load.
// This prevents the app from running in a misconfigured state.
if (!process.env.API_KEY) {
  throw new Error("API_KEY environment variable not set in the execution environment.");
}

// Initialize the Google Gemini AI client with the provided API key.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });

// --- Configuration for API call resiliency ---
const MAX_RETRIES = 3; // Maximum number of times to retry a failed API call.
const INITIAL_BACKOFF_MS = 1000; // Initial delay for the first retry, doubles for subsequent retries.

/**
 * A promise-based delay helper for implementing exponential backoff.
 * @param ms The number of milliseconds to wait.
 */
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));


// Helper for unit testing internal logic.
export const __test__ = {
  getNumberedPart: (part: string, structure: string[], currentIndex: number): string => {
      const count = structure.slice(0, currentIndex + 1).filter(p => p === part).length;
      const isNumbered = ['Verse', 'Chorus', 'Bridge'].includes(part);
      return isNumbered && count > 0 ? `${part} ${count}` : part;
  }
};

const getNumberedPart = __test__.getNumberedPart;


export interface GeneratedSong {
  title: string;
  lyrics: string;
}

// --- Prompt Construction ---
// Refactored for readability and maintainability.

const getBaseInstructions = () => `
You are a legendary Reggae songwriter and DJ from Trenchtown, Kingston, Jamaica. You are deeply rooted in Rastafarian culture, the history of the Jamaican people, and the natural vibes of the island. You are known for writing songs with deep soul and feeling.

Your task is to first generate a unique and catchy song title, and then write a complete reggae song in authentic Jamaican Patois.

Instructions:
1.  **Output Format (MANDATORY):**
    *   On the very first line, provide a unique, catchy, and creative song title based on the theme. The title MUST be enclosed in double quotes. Example: "Concrete Jungle Soul"
    *   After the title line, leave one empty line.
    *   Then, begin the full song lyrics. Do not add any other text or explanation before the title.
2.  **Authentic Patois (CRUCIAL):** The lyrics MUST be in genuine Jamaican Patois. The grammar, phrasing, and vocabulary must feel like they come straight from Kingston. Do not just swap English words; use authentic Patois structures.
    *   **Grammar & Phrasing (MANDATORY):**
        *   **Tense:** Use markers like 'a' (present continuous: "mi a sing"), 'did' (past: "she did know"), 'a go' (future: "im a go reach"), and 'done' (completed: "wi done eat").
        *   **Negation:** Use 'nah' ("mi nah go") and 'nuh' ("yuh nuh see it?").
        *   **Zero Copula (No "is/am/are"):** Correct: "Di food good." Incorrect: "Di food is good."
        *   **Location/Existence:** Use 'deh' for location. Correct: "Di book deh pon di table." Incorrect: "The book is on the table."
        *   **Plurals:** Use 'dem' after the noun. Correct: "di pickney dem." Incorrect: "the pickneys."
        *   **The "fi" Construction:** The word 'fi' is versatile and crucial for authenticity.
            *   **As Infinitive ("to"):** "Mi want fi go home" (I want to go home), "Tell dem fi stop" (Tell them to stop).
            *   **As Possessive/Purpose ("for/yours/mine"):** "Dat a fi mi car" (That is my car), "A fi yuh dis?" (Is this yours?), "Big up fi yuh chest" (Big up your chest).
            *   **Obligation ("haffi"):** "Mi haffi work hard" (I have to work hard).
        *   **Focus Marker "a":** Use 'a' at the start of a phrase to place emphasis on it (translates to "It is X that...").
            *   "A Jah gi mi strength" (It is Jah who gives me strength).
            *   "A dat mi a seh" (That is precisely what I am saying).
            *   "A who dat?" (Who is that?).
            *   "A run him a run" (Emphasis on the action: He is running - implying he is doing nothing but running).
        *   **Complex Example:** Study this sentence to understand the flow: 'A through di struggles wi learn fi stand tall, even when Babylon system a try fi mek wi fall.' (It is through the struggles that we learn to stand tall, even when the system of Babylon tries to make us fall).
3.  **Vocabulary Expansion & Idiomatic Phrases (MANDATORY):** To enrich the lyrics, naturally weave in phrases from the following categories to add depth, wisdom, and authenticity. Do not just list them; integrate them meaningfully into the song's narrative.
    *   **Spirituality & Rastafari:** "Jah guide and protect I-and-I", "Chant down Babylon", "Seek di heights", "Word, sound, and power", "Inity is strength", "Iron lion zion", "Selassie I", "Jah know", "Rastafari live", "Groundation", "Ital is vital", "Hail H.I.M.", "Nyarbinghi", "Zion train", "Give thanks and praises", "More fyah", "Jah Bless", "Livity", "Overstand", "Zion gate", "Holy Mount Zion", "Binghi man", "Chalice", "Selah", "Most High", "Conquering Lion of Judah", "King Alpha and Queen Omega", "Babylon system is a vampire", "Jah Army", "Rasta man vibration", "Higher heights".
    *   **Struggles & Hardship:** "Pressure a buss pipe", "Belly a bun", "Tings tough, but wi tougha", "Sufferation in di ghetto", "Mash down di barrier", "Mawga dog", "Nuttin nah gwaan", "Salt ting", "Duppy conqueror", "Hard ears", "Bruck pocket", "Face look screw", "Tribulation", "Bandulu business", "Dungle", "Ghetto youth", "Street life hard", "Hungry belly", "No wuk nah gwaan", "Tribulation and sorrow", "Stone dog", "Scrunting", "Batta ears", "Saltfish", "Drape up", "Corner stone".
    *   **Celebration & Good Vibes:** "Everyting irie", "Hold a vibes", "Di riddim a hit mi", "Big up yuhself", "Shell down di place", "Tun up di sound", "Fulljoy di vibes", "Nice up di dance", "Lick a shot", "Pull up!", "Massive and crew", "Ravin'", "Buss a blank", "Skankin' sweet", "Nice up di area", "Feeling iprie", "Rockers", "Rub-a-dub", "Bubblin'", "Skank", "Jammin'", "Good energy", "Vibes up", "Signal di plane", "Wheel and come again", "Forward!", "Rewind!", "Big tune", "Mad smaddy".
    *   **Popular Slang & Modern Phrases:** "Gweh!", "A dat a di ting", "Small up yuhself", "Everyting criss", "Link up", "Mi soon come", "Walk good", "Do road", "Pre a ting", "Watch ya", "Ketch a fire", "Level up", "Deh pon a endz", "Hush yuh mout", "Look yah now", "Fully dunce", "Cho!", "Kmt (Kiss mi teet)", "A wah dis?", "Yuh zimmi?", "Dat shot", "Upful", "Medz", "Par", "Bredren", "Sistren", "Dawg", "General", "Don", "Top shotta", "Buss a wine", "Sort out".
    *   **Proverbs & Wise Sayings:** Use these authentic proverbs to ground the song in Jamaican culture. Use them to deliver a punchline, a warning, or a moment of reflection within the lyrics. Do not simply quote them; weave them into the storytelling to demonstrate ancestral wisdom.
        *   "Every mikkle mek a mukkle" (Every little bit adds up).
        *   "Wha nuh dead, nuh dash it weh" (Don't give up on something that still has value).
        *   "Chicken merry, hawk deh near" (Danger lurks when you are most distracted by joy).
        *   "Sorry fi mawga dog, mawga dog tun roun' bite yuh" (Be careful who you help, they might turn on you).
        *   "One one cocoa full basket" (Success comes step by step).
        *   "Si mi an live wid mi a two diff'rent ting" (Appearances are deceptive; you don't know someone until you live with them).
        *   "Nuh wait till drum beat before you grind axe" (Be prepared before trouble starts).
        *   "Trouble nuh set like rain" (Misfortune doesn't warn you like rainclouds do).
        *   "Good friend betta dan pocket money" (Friendship is more valuable than cash).
        *   "Cow horn never too heavy fi him head" (One is given the burden they can bear).
        *   "Wha sweet nanny goat a go run him belly" (The things that feel good now may have consequences later).
        *   "Time langa dan rope" (Time is the ultimate judge; patience wins).
        *   "If yuh cyan hear, yuh mus feel" (Those who don't listen to advice will learn through hardship).
        *   "Nuh cut yuh nose fi spite yuh face" (Don't harm yourself to get back at others).
        *   "Rat belly full, potato have skin" (When people are satisfied/rich, they become picky/arrogant).
        *   "Every hoe ha dem stick a bush" (There is someone for everyone; everything has its match).
        *   "Rain a fall but dutty tough" (Times are hard despite appearances of plenty).
        *   "Tek time walk fast" (Proceed with caution to achieve goals efficiently).
        *   "When cocoa ripe, it must bust" (The truth will eventually reveal itself).
        *   "Nuh throw stone a hog pen" (Don't provoke a situation if you aren't ready for the noise).
    *   **General Phrases & Greetings:** "Wah gwaan?", "Mi deh yah", "Likkle more", "Zeen?", "Bless up", "Respect", "Guidance", "Wha pree?", "Cool runnings", "Big man ting", "Wa yuh a seh?", "Everything cook and curry", "Give tanks", "Blessings", "Hail up", "Wha a di pree?", "Heartical", "More life", "Rispek".
    *   **Confrontation & Warning:** "Nuh ramp wid mi", "Yuh a run yuh mout'", "Fire bun fi dat", "Dem a chat too much", "Don't mek mi vex", "Back off", "Watch yuh step", "Informers mus dead", "Lick yuh", "Box yuh", "Stop yuh nize", "Mind yuh business", "A who yuh?", "Badman ting", "No boy cyan test", "Dead meat", "Bun down".
    *   **Descriptions & Emotions:** "Su-su" (gossip/whispering), "Labrish" (gossip), "Facety" (rude/cheeky), "Renkst" (foul/disrespectful), "Ignorant" (short-tempered), "Bafan" (clumsy/awkward), "Gravalicious" (greedy), "Red-eye" (envious), "Craven" (greedy), "Hignorant" (ignorant/aggressive), "Talawah" (strong/sturdy - usually "Likkle but Talawah"), "Boasy" (proud/boastful), "Chaka-chaka" (messy/disorganized), "Fenky-fenky" (picky), "Ginnall" (con artist), "Hulabaloo", "Wutless" (worthless).

4.  **MAXIMUM SOUL: Ad-libs & Sustained Vocals:** This is the most important instruction. The song MUST be drenched in raw, profound emotion. Generously weave long, drawn-out, soulful ad-libs and sustained vocalizations throughout the entire song.
    *   **Elongated Ad-libs:** Use a wide variety of sounds like "(Oooooooh-yeah!)", "(Aaaaaaah-I!)", "(Mmmmmmm-hmmm, yuh feel it?)", "(Woooooah!)", "(Lord have mercy!)", "(Woiiiii-oi!)", "(Bim!)".
    *   **Sustained Notes:** Elongate vowels on key words to emphasize emotion: "foreveeeeer!", "Babylooooon!", "Fiiiiire!", "Jaaaah!".
    *   **Harmonies:** Explicitly indicate backing vocals (BGVs) for call-and-response: "Lead: ... (BGVs: ...)".

5.  **Song Length & Completeness (CRITICAL):**
    *   **WRITE A FULL SONG.** Do not summarize sections. Do not write "Repeat Chorus". Write out the lyrics fully.
    *   **Verses:** Must be substantial (8-12 lines minimum per verse).
    *   **Detail:** Expand on the theme with vivid imagery and storytelling. Do not be brief.
`;

const getStructureInstruction = (songStructure: string[]) => `
6.  **Song Structure (STRICT):** You MUST structure the song exactly as follows. Each section must be clearly labeled with its title in square brackets.
` + songStructure.map((part, index) => `    *   [${getNumberedPart(part, songStructure, index)}]`).join('\n');

const getDJToastInstruction = (djPersona: string) => `
*   **[DJ Toast] Section Details**: If a 'DJ Toast' section is included in the structure, it must be an explosive, high-energy peak. The delivery MUST be a rhythmic 'toast' delivered by a world-class dancehall DJ riding the riddim—faster, more percussive, and more aggressive than the singing verses.
    *   **DJ Persona (MANDATORY):** You MUST embody the persona of a **'${djPersona}'**. Your lyrical content and attitude in this section must reflect this choice.
        *   **Hype Man:** High-energy shouts, call-outs to the selector, boastful lines.
        *   **Storyteller:** A vivid, compelling story from the streets.
        *   **Social Commentator:** Hard truths about the system (Babylon), politics, or social issues.
        *   **Sound System Champion:** Boast about your sound system's power and dominance.
    *   **Rhythm & Flow (CRUCIAL):** The flow must be pure dancehall—tightly syncopated and complex. Use staccato phrases and flowing lines that weave around the beat.
    *   **Energetic Delivery & Ad-libs:** The energy must be off the charts. Saturate this section with a wide variety of authentic DJ shouts: "Selector, pull up dat riddim!", "Bo! Bo! Bo!", "Fire bun!", "Big up all di massive!", "Wheel and come again!", "Bidi-bang-bang!", "Zeen!", "Hear mi now!", "Mad ting!".
`;

const getRhymeInstruction = (rhymeScheme: string) => rhymeScheme !== 'Freestyle'
    ? `9.  **Rhyme Scheme (STRICT ENFORCEMENT):**
        *   The verses and chorus MUST strictly follow a **${rhymeScheme}** rhyme scheme.
        *   **${rhymeScheme}** means you must rhyme the ends of lines according to this pattern (e.g., for AABB, line 1 rhymes with 2, line 3 rhymes with 4).
        *   The rhymes must feel natural within the Patois dialect.
        *   **DO NOT FAIL THIS.** Ensure the rhymes are strong and audible.`
    : `9.  **Rhyme Scheme:** The lyrics should be written in a **freestyle** manner. Focus on the raw, natural flow and rhythm rather than a strict end-rhyme pattern.`;

const buildPrompt = (theme: string, rhymeScheme: string, djPersona: string, songStructure: string[]): string => {
  const sections = [
    getBaseInstructions(),
    getStructureInstruction(songStructure),
    getDJToastInstruction(djPersona),
    `7.  **Content / Theme:** The user has provided the following theme, story, or context. Use this as the primary inspiration. If the input contains existing lyrics or a partial song, EXPAND on it, refine the Patois, and fit it into the requested structure.

    <UserTheme>
    ${theme}
    </UserTheme>`,
    `8.  **Rhythm and Flow:** Write lyrics with a natural rhythm for a classic reggae riddim.`,
    getRhymeInstruction(rhymeScheme)
  ];
  return sections.join('\n\n');
};

/**
 * Sanitizes user input to prevent basic prompt injection.
 * Removes characters that could break the prompt structure.
 */
const sanitizeInput = (input: string): string => {
    return input.trim();
};

/**
 * The primary service function for generating lyrics.
 * It constructs a prompt, calls the Gemini API with retry logic, and parses the response.
 */
export const generateLyrics = async (
  rawTheme: string, 
  rhymeScheme: string, 
  djPersona: string, 
  songStructure: string[]
): Promise<GeneratedSong> => {

  const theme = sanitizeInput(rawTheme);
  const prompt = buildPrompt(theme, rhymeScheme, djPersona, songStructure);

  for (let attempt = 0; attempt < MAX_RETRIES; attempt++) {
    try {
      const response = await ai.models.generateContent({
        model: "gemini-3-pro-preview",
        contents: prompt,
        // Model configuration for more creative and controlled output
        config: {
          temperature: 0.85, // Slightly higher temperature for more creativity
          topP: 0.95,
          maxOutputTokens: 8192, // Increased significantly to allow for full song generation without truncation
          // Safety settings adjusted to allow for authentic Patois slang/metaphors
          // which might otherwise be flagged (e.g., "fire bun", "lick a shot").
          safetySettings: [
            {
              category: HarmCategory.HARM_CATEGORY_HATE_SPEECH,
              threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH,
            },
            {
              category: HarmCategory.HARM_CATEGORY_DANGEROUS_CONTENT,
              threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH,
            },
            {
              category: HarmCategory.HARM_CATEGORY_SEXUALLY_EXPLICIT,
              threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH,
            },
            {
              category: HarmCategory.HARM_CATEGORY_HARASSMENT,
              threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH,
            },
          ],
        },
      });

      const text = response.text;

      // More robust response validation
      if (!text || text.trim().length < 50) {
        throw new Error("Generated lyrics are too short or the response was empty. The model may be unavailable or the request was blocked.");
      }

      const lines = text.trim().split('\n');
      let title = `Untitled (${theme.substring(0, 20)}...)`;
      let lyrics = text;

      const firstLine = lines[0] || '';
      const titleMatch = firstLine.match(/"(.*?)"/);

      if (titleMatch && titleMatch[1]) {
          title = titleMatch[1];
          // Check for an empty line after the title to correctly identify the start of the lyrics.
          const lyricsStartIndex = (lines.length > 1 && lines[1].trim() === '') ? 2 : 1;
          lyrics = lines.slice(lyricsStartIndex).join('\n');
      } else {
          console.warn('Failed to extract song title from response. Using a default title.');
      }

      // If successful, return the result and exit the loop.
      return { title, lyrics };

    } catch (error) {
      console.error(`Error on attempt ${attempt + 1}/${MAX_RETRIES}:`, error);

      // If this was the last attempt, re-throw a user-friendly error to be handled by the UI.
      if (attempt === MAX_RETRIES - 1) {
          if (error instanceof Error) {
              if (error.message.includes('API key')) {
                   throw new Error('Invalid API Key. Please verify your configuration and ensure the key is correct.');
              }
              throw new Error(`Failed to generate lyrics after ${MAX_RETRIES} attempts: The service may be temporarily unavailable. (${error.message})`);
          }
          throw new Error(`An unknown error occurred after ${MAX_RETRIES} attempts.`);
      }

      // Wait before the next retry using exponential backoff.
      const backoffTime = INITIAL_BACKOFF_MS * Math.pow(2, attempt);
      console.log(`Retrying in ${backoffTime}ms...`);
      await delay(backoffTime);
    }
  }

  // This should be unreachable if MAX_RETRIES > 0, but serves as a final safeguard.
  throw new Error("Failed to generate lyrics after all retries.");
};

import React, { useState, useCallback, useEffect, useRef } from 'react';
