      <div id="pdf-content" style={{
            position: 'absolute', left: '-9999px', width: '8.27in', minHeight: '11.69in', padding: '1in',
            backgroundColor: 'white', color: 'black', fontSize: '12pt', lineHeight: '1.6',
      }}>
          <h1 style={{ fontFamily: 'serif', fontSize: '24pt', fontWeight: 'bold', borderBottom: '2px solid black', paddingBottom: '10px', marginBottom: '20px' }}>{songTitle || 'Untitled'}</h1>
          <p style={{fontFamily: 'sans-serif'}}><strong>Artist:</strong> {artistName || 'N/A'}</p>
          <p style={{fontFamily: 'sans-serif'}}><strong>Album:</strong> {albumName || 'N/A'}</p>
          <p style={{fontFamily: 'sans-serif', whiteSpace: 'pre-wrap'}}><strong>Theme:</strong> {theme}</p>
          <br />
          <div style={{ fontFamily: 'serif', whiteSpace: 'pre-wrap', fontSize: '12pt' }}>
              {formatLyricsForPdf(lyrics)}
          </div>
      </div>

      <div className="rasta-stripes"></div>
      <div className="container mx-auto p-4 md:p-8 max-w-3xl min-h-screen">
        <header className="mb-8 relative">
          <div className="absolute top-0 right-0 text-right text-sm z-10">
            <p className="text-secondary">Welcome, <span className="font-bold text-title">{currentUser}</span></p>
            <button onClick={handleLogout} className="text-red-400 hover:underline">Logout</button>
          </div>
          <div className="absolute top-0 left-0 text-left text-sm z-10">
            <ThemeSwitcher onThemeChange={setAppTheme} />
          </div>

          <div className="flex flex-col justify-center items-center pt-8 md:pt-4 text-center">
            <h1 className="title-font text-5xl md:text-6xl font-bold tracking-tight">
              PATOIS Lyricist
            </h1>
            <div className="my-4">
              <HeaderIcon />
            </div>
            <p className="text-accent text-lg font-medium">Crafting Authentic Reggae Riddims</p>
          </div>
           <nav className="flex justify-center gap-4 mt-4 border-b border-primary pb-2">
              <button onClick={() => setCurrentView('main')} className={`px-4 py-1 rounded-md text-sm font-semibold transition-all ${currentView === 'main' ? 'bg-title text-black' : 'hover:bg-gray-700/50'}`}>Generator</button>
              {currentUserRole === 'admin' && (
                <button onClick={() => setCurrentView('admin')} className={`px-4 py-1 rounded-md text-sm font-semibold transition-all ${currentView === 'admin' ? 'bg-title text-black' : 'hover:bg-gray-700/50'}`}>Admin Panel</button>
              )}
              <button onClick={() => setCurrentView('testing')} className={`px-4 py-1 rounded-md text-sm font-semibold transition-all ${currentView === 'testing' ? 'bg-title text-black' : 'hover:bg-gray-700/50'}`}>Diagnostics</button>
            </nav>
        </header>

        {renderView()}

        <footer className="text-center mt-12 text-sm text-secondary pb-8">
          <p>Lyrics generated by AI in Kingston spirit. For inspiration only.</p>
          <p className="mt-1 opacity-75">Powered by Google Gemini 3 Pro</p>
        </footer>
      </div>
    </>
  );
};

export default App;

import React, { useState, useCallback, useEffect, useRef } from 'react';
import { generateLyrics } from './services/geminiService';
import { logAction } from './services/auditLogService';
import Spinner from './components/Spinner';
import LyricsOutput from './components/LyricsOutput';
import History from './components/History';
import StructureBuilder from './components/StructureBuilder';
import HeaderIcon from './components/HeaderIcon';
import ThemeSwitcher from './components/ThemeSwitcher';
import AdminPanel from './components/AdminPanel';
import TestPanel from './components/TestPanel';
import html2canvas from 'html2canvas';
import jsPDF from 'jspdf';

export interface HistoryEntry {
  id: number;
  theme: string;
  songTitle: string;
  artistName: string;
  albumName: string;
  lyrics: string;
  timestamp: string;
  rhymeScheme: string;
  djPersona: string;
  songStructure: string[];
}

export interface User {
  password: string;
  role: 'user' | 'admin';
}

export type Theme = 'dark' | 'light' | 'high-contrast';
type View = 'main' | 'admin' | 'testing';

// FIX: Add type definitions for the Web Speech API which are not part of the default TS DOM typings.
interface SpeechRecognitionAlternative {
  readonly transcript: string;
  readonly confidence: number;
}

interface SpeechRecognitionResult {
  readonly isFinal: boolean;
  readonly length: number;
  item(index: number): SpeechRecognitionAlternative;
  [index: number]: SpeechRecognitionAlternative;
}

interface SpeechRecognitionResultList {
  readonly length: number;
  item(index: number): SpeechRecognitionResult;
  [index: number]: SpeechRecognitionResult;
}

interface SpeechRecognitionErrorEvent extends Event {
  readonly error: string;
}

interface SpeechRecognitionEvent extends Event {
  readonly resultIndex: number;
  readonly results: SpeechRecognitionResultList;
}

interface SpeechRecognition extends EventTarget {
  continuous: boolean;
  interimResults: boolean;
  lang: string;
  onstart: ((this: SpeechRecognition, ev: Event) => any) | null;
  onend: ((this: SpeechRecognition, ev: Event) => any) | null;
  onerror: ((this: SpeechRecognition, ev: SpeechRecognitionErrorEvent) => any) | null;
  onresult: ((this: SpeechRecognition, ev: SpeechRecognitionEvent) => any) | null;
  start(): void;
  stop(): void;
}

interface SpeechRecognitionStatic {
  new (): SpeechRecognition;
}

declare global {
  interface Window {
    SpeechRecognition: SpeechRecognitionStatic;
    webkitSpeechRecognition: SpeechRecognitionStatic;
  }
}

const App: React.FC = () => {
  // Auth State
  const [currentUser, setCurrentUser] = useState<string | null>(() => localStorage.getItem('patoisLyricistCurrentUser'));
  const [currentUserRole, setCurrentUserRole] = useState<'user' | 'admin'>('user');
  const [authView, setAuthView] = useState<'login' | 'register'>('login');
  const [authUsername, setAuthUsername] = useState('');
  const [authPassword, setAuthPassword] = useState('');
  const [authError, setAuthError] = useState<string | null>(null);

  // App State
  const [theme, setTheme] = useState<string>('');
  const [rhymeScheme, setRhymeScheme] = useState<string>('AABB');
  const [djPersona, setDjPersona] = useState<string>('Hype Man');
  const [songStructure, setSongStructure] = useState<string[]>([
    'Intro', 'Verse', 'Chorus', 'Verse', 'Chorus', 'DJ Toast', 'Outro'
  ]);
  const [songTitle, setSongTitle] = useState<string>('');
  const [artistName, setArtistName] = useState<string>('');
  const [albumName, setAlbumName] = useState<string>('');
  const [lyrics, setLyrics] = useState<string>('');
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [isStructureVisible, setIsStructureVisible] = useState(true);
  const [showLoadConfirmation, setShowLoadConfirmation] = useState<boolean>(false);
  const [currentView, setCurrentView] = useState<View>('main');
  const [isDownloadMenuOpen, setIsDownloadMenuOpen] = useState(false);
  const [isDownloadingPdf, setIsDownloadingPdf] = useState(false);

  // Voice Input State
  const [isListening, setIsListening] = useState(false);
  const [isSpeechRecognitionSupported, setIsSpeechRecognitionSupported] = useState(false);
  const recognitionRef = useRef<SpeechRecognition | null>(null);
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  const downloadMenuRef = useRef<HTMLDivElement>(null);

  const [history, setHistory] = useState<HistoryEntry[]>([]);

  // Constants for limits
  const THEME_LIMIT = 3000;
  const TITLE_LIMIT = 80;
  const ARTIST_LIMIT = 50;
  const ALBUM_LIMIT = 50;

  // Load user data and history on mount
  useEffect(() => {
    const loggedInUser = localStorage.getItem('patoisLyricistCurrentUser');
    if (loggedInUser) {
      const users = getUsers();
      const user = users[loggedInUser];
      if (user) {
        setCurrentUser(loggedInUser);
        setCurrentUserRole(user.role);
        const savedHistory = localStorage.getItem(`patoisLyricistHistory_${loggedInUser}`);
        setHistory(savedHistory ? JSON.parse(savedHistory) : []);
      } else {
        handleLogout();
      }
    }

    const savedTheme = localStorage.getItem('patoisLyricistTheme') as Theme || 'dark';
    setAppTheme(savedTheme);

    const SpeechRecognitionAPI = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (SpeechRecognitionAPI) {
      setIsSpeechRecognitionSupported(true);
    }
  }, []);

  useEffect(() => {
    if (!currentUser) return;
    try {
      localStorage.setItem(`patoisLyricistHistory_${currentUser}`, JSON.stringify(history));
    } catch (error) {
      console.error("Failed to save history to localStorage", error);
    }
  }, [history, currentUser]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
        if (downloadMenuRef.current && !downloadMenuRef.current.contains(event.target as Node)) {
            setIsDownloadMenuOpen(false);
        }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => {
        document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  useEffect(() => {
    if (isListening && textareaRef.current) {
      textareaRef.current.scrollTop = textareaRef.current.scrollHeight;
    }
  }, [theme, isListening]);

  const setAppTheme = (themeName: Theme) => {
      document.body.setAttribute('data-theme', themeName);
      localStorage.setItem('patoisLyricistTheme', themeName);
  };

  const handleGenerate = useCallback(async () => {
    if (!theme.trim()) {
      setError('Please enter a theme to generate lyrics.');
      return;
    }
    if (songStructure.length === 0) {
      setError('Please add at least one part to the song structure.');
      return;
    }
    if (isLoading) return;

    setIsLoading(true);
    setError(null);
    setLyrics('');

    try {
      const { title: generatedTitle, lyrics: generatedLyrics } = await generateLyrics(theme, rhymeScheme, djPersona, songStructure);
      setLyrics(generatedLyrics);
      setSongTitle(generatedTitle);

      const newHistoryEntry: HistoryEntry = {
        id: Date.now(),
        theme,
        songTitle: generatedTitle,
        artistName,
        albumName,
        lyrics: generatedLyrics,
        timestamp: new Date().toISOString(),
        rhymeScheme,
        djPersona,
        songStructure,
      };
      setHistory(prevHistory => [newHistoryEntry, ...prevHistory].slice(0, 50));
    } catch (err) {
      if (err instanceof Error) {
        setError(err.message);
      } else {
        setError('An unknown error occurred.');
      }
      setLyrics('Failed to generate lyrics. Please check your API key and try again.');
    } finally {
      setIsLoading(false);
    }
  }, [theme, rhymeScheme, djPersona, songStructure, artistName, albumName, isLoading]);

  const generateFileContent = (format: 'txt' | 'md'): string => {
    let content = '';
    const headerParts = [];
    const md = format === 'md';
    const cleanTheme = theme.trim().replace(/[\r\n]+/g, ' ');

    if (songTitle.trim()) headerParts.push(md ? `# ${songTitle.trim()}` : `Title: ${songTitle.trim()}`);
    if (cleanTheme) headerParts.push(md ? `**Theme:** ${cleanTheme}` : `Theme: ${cleanTheme}`);
    if (artistName.trim()) headerParts.push(md ? `**Artist:** ${artistName.trim()}` : `Artist: ${artistName.trim()}`);
    if (albumName.trim()) headerParts.push(md ? `**Album:** ${albumName.trim()}` : `Album: ${albumName.trim()}`);
    if (rhymeScheme) headerParts.push(md ? `**Rhyme Scheme:** ${rhymeScheme}` : `Rhyme Scheme: ${rhymeScheme}`);
    if (djPersona) headerParts.push(md ? `**DJ Persona:** ${djPersona}` : `DJ Persona: ${djPersona}`);
    if (songStructure.length > 0) {
        const structureString = songStructure.join(' → ');
        headerParts.push(md ? `**Structure:** ${structureString}` : `Structure: ${structureString}`);
    }

    content += headerParts.join(md ? '\n\n' : '\n');
    if (headerParts.length > 0) {
        content += md ? '\n\n---\n\n' : '\n----------------------------------\n\n';
    }

    let formattedLyrics = lyrics;
    if (md) {
        formattedLyrics = lyrics.replace(/(\[.*?\])/g, '\n## $1\n');
    }

    content += formattedLyrics;
    return content;
  }

  const handleToggleListening = useCallback(() => {
    if (isLoading) return;

    if (isListening) {
      recognitionRef.current?.stop();
      return;
    }

    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SpeechRecognition) {
      setError("Speech recognition is not supported in your browser.");
      return;
    }

    const recognition = new SpeechRecognition();
    recognitionRef.current = recognition;
    recognition.continuous = true;
    recognition.interimResults = true;
    recognition.lang = 'en-US';

    recognition.onstart = () => {
      setIsListening(true);
      setError(null);
    };

    recognition.onend = () => {
      recognitionRef.current = null;
      setIsListening(false);
    };

    recognition.onerror = (event) => {
      if (event.error !== 'no-speech') {
        if (event.error === 'not-allowed' || event.error === 'service-not-allowed') {
          setError("Microphone access was denied. Please allow microphone access.");
        } else {
          setError(`Speech recognition error: ${event.error}`);
        }
      }
      setIsListening(false);
    };

    recognition.onresult = (event) => {
      let interimTranscript = '';
      let finalTranscript = '';

      for (let i = event.resultIndex; i < event.results.length; i++) {
        const transcriptChunk = event.results[i][0].transcript;
        if (event.results[i].isFinal) {
          finalTranscript += transcriptChunk;
        } else {
          interimTranscript += transcriptChunk;
        }
      }

      setTheme((prev) => {
        const base = prev.endsWith(' ') || prev === '' ? prev : prev + ' ';
        const updated = base + finalTranscript + interimTranscript;
        return updated.length > THEME_LIMIT ? updated.substring(0, THEME_LIMIT) : updated;
      });
    };

    recognition.start();
  }, [isLoading, isListening]);

  const handleDownload = async (format: 'txt' | 'md' | 'pdf') => {
      if (!lyrics || lyrics.trim() === 'Your lyrics will appear here...') {
          setError('No lyrics to download.');
          return;
      }
      setIsDownloadMenuOpen(false);
      setError(null);

      const safeFilename = (
          songTitle.trim() || 
          theme.trim().slice(0, 30) || 
          'reggae-lyrics'
      ).replace(/[^a-z0-9]/gi, '_').toLowerCase();

      if (format === 'txt' || format === 'md') {
          const content = generateFileContent(format);
          const mimeType = format === 'txt' ? 'text/plain' : 'text/markdown';
          const blob = new Blob([content], { type: `${mimeType};charset=utf-8` });
          const link = document.createElement('a');
          link.href = URL.createObjectURL(blob);
          link.download = `${safeFilename}.${format}`;
          document.body.appendChild(link);
          link.click();
          document.body.removeChild(link);
          URL.revokeObjectURL(link.href);
      } else if (format === 'pdf') {
          setIsDownloadingPdf(true);
          const input = document.getElementById('pdf-content');
          if (!input) {
              setError('PDF generation failed: content element not found.');
              setIsDownloadingPdf(false);
              return;
          }
          try {
              const canvas = await html2canvas(input, { scale: 2, useCORS: true });
              const imgData = canvas.toDataURL('image/png');
              const pdf = new jsPDF('p', 'pt', 'a4');
              const pdfWidth = pdf.internal.pageSize.getWidth();
              const pdfHeight = pdf.internal.pageSize.getHeight();
              const canvasWidth = canvas.width;
              const canvasHeight = canvas.height;
              const ratio = canvasWidth / pdfWidth;
              const imgHeight = canvasHeight / ratio;
              let heightLeft = imgHeight;
              let position = 0;
              pdf.addImage(imgData, 'PNG', 0, position, pdfWidth, imgHeight);
              heightLeft -= pdfHeight;
              while (heightLeft > 0) {
                  position = position - pdfHeight;
                  pdf.addPage();
                  pdf.addImage(imgData, 'PNG', 0, position, pdfWidth, imgHeight);
                  heightLeft -= pdfHeight;
              }
              pdf.save(`${safeFilename}.pdf`);
          } catch (err) {
              console.error("PDF Generation Error:", err);
              setError('An error occurred while generating the PDF.');
          } finally {
              setIsDownloadingPdf(false);
          }
      }
  };

  const handleLoadHistory = (entry: HistoryEntry) => {
    setTheme(entry.theme);
    setSongTitle(entry.songTitle);
    setArtistName(entry.artistName);
    setAlbumName(entry.albumName);
    setLyrics(entry.lyrics);
    setRhymeScheme(entry.rhymeScheme || 'AABB');
    setDjPersona(entry.djPersona || 'Hype Man');
    setSongStructure(entry.songStructure || ['Intro', 'Verse', 'Chorus', 'Verse', 'Chorus', 'DJ Toast', 'Outro']);
    setCurrentView('main');
    window.scrollTo(0, 0);
    setShowLoadConfirmation(true);
    setTimeout(() => setShowLoadConfirmation(false), 2500);
  };

  const handleClearHistory = () => {
    setHistory([]);
  };

  const getUsers = (): Record<string, User> => {
    try {
      const users = localStorage.getItem('patoisLyricistUsers');
      return users ? JSON.parse(users) : {};
    } catch {
      return {};
    }
  };

  const handleRegister = () => {
    if (!authUsername.trim() || !authPassword.trim()) {
      setAuthError('Username and password cannot be empty.');
      return;
    }
    const users = getUsers();
    if (users[authUsername]) {
      setAuthError('Username already exists.');
      return;
    }
    users[authUsername] = {
        password: authPassword,
        role: authUsername === 'admin' ? 'admin' : 'user'
    };
    localStorage.setItem('patoisLyricistUsers', JSON.stringify(users));
    logAction('system', 'User Registered', { username: authUsername });
    handleLogin();
  };

  const handleLogin = () => {
    const users = getUsers();
    const user = users[authUsername];
    if (user && user.password === authPassword) {
      localStorage.setItem('patoisLyricistCurrentUser', authUsername);
      setCurrentUser(authUsername);
      setCurrentUserRole(user.role);
      setAuthUsername('');
      setAuthPassword('');
      setAuthError(null);
      const savedHistory = localStorage.getItem(`patoisLyricistHistory_${authUsername}`);
      setHistory(savedHistory ? JSON.parse(savedHistory) : []);
      logAction(authUsername, 'User Login', { success: true });
    } else {
      setAuthError('Invalid username or password.');
      logAction(authUsername, 'User Login Failed', { success: false });
    }
  };

  const handleLogout = () => {
    if (isListening) recognitionRef.current?.stop();
    logAction(currentUser || 'unknown', 'User Logout', {});
    localStorage.removeItem('patoisLyricistCurrentUser');
    setCurrentUser(null);
    setCurrentUserRole('user');
    setHistory([]);
    setTheme('');
    setLyrics('');
    setError(null);
    setSongTitle('');
    setArtistName('');
    setAlbumName('');
    setCurrentView('main');
  };

  if (!currentUser) {
    const handleAuthSubmit = (e: React.FormEvent) => {
      e.preventDefault();
      if (authView === 'login') {
        handleLogin();
      } else {
        handleRegister();
      }
    };

    return (
      <div className="login-background">
        <div className="music-notes note1">♪</div>
        <div className="music-notes note2">♫</div>
        <div className="music-notes note3">♪</div>
        <div className="login-container">
          <div className="login-header">
            <div className="login-logo">PATOISLyricist</div>
            <div className="login-subtitle">Crafting Authentic Reggae Riddims</div>
          </div>
          <div className="login-card">
            <h2 className="card-title">{authView === 'login' ? 'Welcome Back' : 'Create Account'}</h2>
             {authError && <p className="text-red-400 text-center mb-4 bg-red-900/50 p-2 rounded-lg">{authError}</p>}
            <form onSubmit={handleAuthSubmit}>
              <div className="form-group">
                <div className="input-wrapper">
                  <input type="text" id="username" placeholder="Username" required value={authUsername} onChange={(e) => setAuthUsername(e.target.value)} />
                  <span className="input-icon">👤</span>
                </div>
              </div>
              <div className="form-group">
                <div className="input-wrapper">
                  <input type="password" id="password" placeholder="Password" required value={authPassword} onChange={(e) => setAuthPassword(e.target.value)} />
                  <span className="input-icon">🔒</span>
                </div>
              </div>
              <button type="submit" className="login-btn">{authView === 'login' ? 'Login' : 'Register'}</button>
              <div className="register-link">
                {authView === 'login' ? (
                  <>Don't have an account? <a onClick={() => { setAuthView('register'); setAuthError(null); }}>Register here</a></>
                ) : (
                  <>Already have an account? <a onClick={() => { setAuthView('login'); setAuthError(null); }}>Login here</a></>
                )}
              </div>
            </form>
          </div>
        </div>
      </div>
    );
  }

    const formatLyricsForPdf = (lyricsText: string) => {
      if (!lyricsText) return null;
      return lyricsText.split('\n').map((line, index) => {
          const partMatch = line.match(/^(\[.*\])$/);
          if (partMatch) {
              return (
                  <React.Fragment key={index}>
                      {index > 0 && <br />}
                      <strong style={{ display: 'block', marginTop: '1em', marginBottom: '0.5em', fontFamily: 'sans-serif' }}>{partMatch[1]}</strong>
                  </React.Fragment>
              );
          }
          return <React.Fragment key={index}>{line}<br /></React.Fragment>;
      });
    };

  const renderView = () => {
    switch(currentView) {
      case 'admin':
        return <AdminPanel currentUser={currentUser} />;
      case 'testing':
        return <TestPanel />;
      case 'main':
      default:
        return (
          <main>
            <div className="bg-card backdrop-blur-sm p-6 rounded-xl shadow-2xl border border-primary">
              <div className="flex justify-between items-center mb-2">
                <label htmlFor="themeInput" className="block text-lg font-semibold">
                  Describe your song's theme:
                </label>
                {isListening && (
                  <span className="flex items-center text-red-500 text-xs font-bold animate-pulse">
                    <span className="w-2 h-2 bg-red-500 rounded-full mr-1"></span>
                    LIVE TRANSCRIPTION ACTIVE
                  </span>
                )}
              </div>
              <div className="relative">
                <textarea
                  id="themeInput"
                  ref={textareaRef}
                  value={theme}
                  onChange={(e) => setTheme(e.target.value)}
                  placeholder="A soulful story about struggle, hope, and Redemption in Kingston..."
                  className={`w-full p-3 pr-12 bg-input border-2 rounded-lg focus:outline-none transition duration-300 placeholder-color resize-y ${isListening ? 'border-red-500 ring-1 ring-red-500' : 'border-primary border-focus'}`}
                  rows={5}
                  maxLength={THEME_LIMIT}
                  disabled={isLoading}
                />
                {isSpeechRecognitionSupported && (
                  <button
                    type="button"
                    onClick={handleToggleListening}
                    disabled={isLoading}
                    className={`mic-button ${isListening ? 'listening' : ''}`}
                    title={isListening ? 'Stop Listening' : 'Start Voice Dictation'}
                    aria-label={isListening ? 'Stop dictation' : 'Start dictation'}
                  >
                    <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20" xmlns="http://www.w3.org/2000/svg"><path fillRule="evenodd" d="M7 4a3 3 0 016 0v4a3 3 0 11-6 0V4zm4 10.93A7.001 7.001 0 0017 8h-1a6 6 0 11-12 0H3a7.001 7.001 0 006 6.93V17H7a1 1 0 100 2h6a1 1 0 100-2h-2v-2.07z" clipRule="evenodd"></path></svg>
                  </button>
                )}
              </div>
              <div className="mt-2">
                <div className="flex justify-between items-center text-xs font-medium mb-1">
                  <span className={`${isListening ? 'text-red-400 font-bold' : 'text-secondary italic'}`}>
                    {isListening ? 'Listening for your voice...' : 'Type or use voice dictation'}
                  </span>
                  <span className={`${theme.length >= THEME_LIMIT ? 'text-red-500' : theme.length > THEME_LIMIT * 0.9 ? 'text-yellow-500' : 'text-secondary'}`}>
                    {theme.length} / {THEME_LIMIT}
                  </span>
                </div>
                <div className="w-full h-1.5 bg-gray-700 rounded-full overflow-hidden">
                  <div 
                    className={`h-full transition-all duration-300 ease-out ${theme.length >= THEME_LIMIT ? 'bg-red-500' : theme.length > THEME_LIMIT * 0.9 ? 'bg-yellow-500' : 'bg-green-500'}`}
                    style={{ width: `${Math.min((theme.length / THEME_LIMIT) * 100, 100)}%` }}
                  ></div>
                </div>
              </div>

              <div className="grid md:grid-cols-2 gap-4 mt-4">
                <div>
                  <label htmlFor="rhymeSchemeSelect" className="block text-sm font-semibold mb-2 text-secondary">
                    Rhyme Scheme
                  </label>
                  <select
                    id="rhymeSchemeSelect"
                    value={rhymeScheme}
                    onChange={(e) => setRhymeScheme(e.target.value)}
                    className="w-full p-3 bg-input border-2 border-primary rounded-lg focus:outline-none border-focus transition duration-300"
                    disabled={isLoading}
                    aria-label="Select a rhyme scheme"
                  >
                    <option value="AABB">AABB (Couplets)</option>
                    <option value="ABAB">ABAB (Alternate)</option>
                    <option value="ABCB">ABCB (Ballad)</option>
                    <option value="AAAA">AAAA (Monorhyme)</option>
                    <option value="AAAB">AAAB (Limerick-like)</option>
                    <option value="ABBA">ABBA (Enclosed)</option>
                    <option value="Freestyle">Freestyle (No strict rhyme)</option>
                  </select>
                </div>
                <div>
                  <label htmlFor="djPersonaSelect" className="block text-sm font-semibold mb-2 text-secondary">
                    DJ Persona
                  </label>
                  <select
                    id="djPersonaSelect"
                    value={djPersona}
                    onChange={(e) => setDjPersona(e.target.value)}
                    className="w-full p-3 bg-input border-2 border-primary rounded-lg focus:outline-none border-focus transition duration-300"
                    disabled={isLoading}
                    aria-label="Select a DJ persona"
                  >
                    <option value="Hype Man">Hype Man</option>
                    <option value="Storyteller">Storyteller</option>
                    <option value="Social Commentator">Social Commentator</option>
                    <option value="Sound System Champion">Sound System Champion</option>
                  </select>
                </div>
              </div>

              <div className="mt-4 pt-4 border-t border-primary">
                <button
                  onClick={() => setIsStructureVisible(!isStructureVisible)}
                  className="w-full flex justify-between items-center text-left text-sm font-semibold mb-3 text-secondary hover:text-primary transition-colors"
                  aria-expanded={isStructureVisible}
                >
                  <span>Song Structure Builder</span>
                  <span className="text-lg" style={{ transform: isStructureVisible ? 'rotate(180deg)' : 'rotate(0deg)', transition: 'transform 0.2s ease-in-out' }}>
                    ▼
                  </span>
                </button>
                {isStructureVisible && (
                  <div>
                    <StructureBuilder 
                      structure={songStructure}
                      setStructure={setSongStructure}
                      disabled={isLoading}
                    />
                  </div>
                )}
              </div>

              <div className="mt-4 pt-4 border-t border-primary">
                  <p className="text-sm font-semibold mb-3 text-secondary">Song Branding (Optional)</p>
                  <div className="grid md:grid-cols-3 gap-4">
                      <div className="relative">
                        <input
                            type="text"
                            value={songTitle}
                            onChange={(e) => setSongTitle(e.target.value)}
                            placeholder="Song Title"
                            maxLength={TITLE_LIMIT}
                            className="w-full p-3 bg-input border-2 border-primary rounded-lg focus:outline-none border-focus transition duration-300 placeholder-color text-sm"
                            disabled={isLoading}
                        />
                        <div className="absolute right-2 bottom-1 text-[10px] text-secondary opacity-60">
                          {songTitle.length}/{TITLE_LIMIT}
                        </div>
                      </div>
                      <div className="relative">
                        <input
                            type="text"
                            value={artistName}
                            onChange={(e) => setArtistName(e.target.value)}
                            placeholder="Artist Name"
                            maxLength={ARTIST_LIMIT}
                            className="w-full p-3 bg-input border-2 border-primary rounded-lg focus:outline-none border-focus transition duration-300 placeholder-color text-sm"
                            disabled={isLoading}
                        />
                        <div className="absolute right-2 bottom-1 text-[10px] text-secondary opacity-60">
                          {artistName.length}/{ARTIST_LIMIT}
                        </div>
                      </div>
                      <div className="relative">
                        <input
                            type="text"
                            value={albumName}
                            onChange={(e) => setAlbumName(e.target.value)}
                            placeholder="Album Name"
                            maxLength={ALBUM_LIMIT}
                            className="w-full p-3 bg-input border-2 border-primary rounded-lg focus:outline-none border-focus transition duration-300 placeholder-color text-sm"
                            disabled={isLoading}
                        />
                        <div className="absolute right-2 bottom-1 text-[10px] text-secondary opacity-60">
                          {albumName.length}/{ALBUM_LIMIT}
                        </div>
                      </div>
                  </div>
              </div>

              <div className="mt-6">
                 {isLoading ? (
                    <div className="w-full bg-green-800 text-white font-bold py-3 px-4 rounded-lg flex justify-center items-center shadow-lg">
                        <div className="w-6 h-6 border-2 border-white/50 border-t-white rounded-full animate-spin mr-2"></div>
                        Vibing with Jah... Generating Lyrics
                    </div>
                ) : (
                    <button
                    onClick={handleGenerate}
                    className="w-full bg-green-600 hover:bg-green-700 text-white font-bold py-3 px-4 rounded-lg shadow-lg transition-all transform hover:scale-[1.02] active:scale-[0.98] duration-300 ease-in-out uppercase tracking-wider"
                    >
                    Create Riddim Lyrics
                    </button>
                )}
              </div>
            </div>

            <div className="mt-8">
              <h2 className="text-3xl font-bold mb-4 text-center text-title">
                The Roots Records
              </h2>
              {isLoading && <Spinner />}
              <div aria-live="polite">
                {!isLoading && error && (
                  <p role="alert" className="text-red-400 text-center mt-4 bg-red-900/50 p-3 rounded-lg border border-red-500/50">{error}</p>
                )}
              </div>
              {!isLoading && (
                <div id="lyricsOutput" className="mt-4">
                  <LyricsOutput lyrics={lyrics || 'Your lyrics will appear here... Share your vision above.'} />
                </div>
              )}

              {!isLoading && lyrics && (
                <div className="text-center mt-6" ref={downloadMenuRef}>
                    <div className="relative inline-block text-left">
                        <button
                            type="button"
                            onClick={() => setIsDownloadMenuOpen(!isDownloadMenuOpen)}
                            className="bg-yellow-600 hover:bg-yellow-700 text-gray-900 font-bold py-2 px-6 rounded-lg shadow-lg transition-transform transform hover:scale-105 duration-300 ease-in-out inline-flex items-center"
                        >
                            <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"></path></svg>
                            Export Dub
                            <svg className="-mr-1 ml-2 h-5 w-5" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor">
                                <path fillRule="evenodd" d="M5.293 7.293a1 1 0 011.414 0L10 10.586l3.293-3.293a1 1 0 111.414 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 010-1.414z" clipRule="evenodd" />
                            </svg>
                        </button>

                        {isDownloadMenuOpen && (
                            <div className="origin-top-right absolute right-0 mt-2 w-56 rounded-md shadow-lg bg-card ring-1 ring-black ring-opacity-5 focus:outline-none z-20 border border-primary">
                                <div className="py-1" role="none">
                                    <button onClick={() => handleDownload('txt')} className="w-full text-left text-primary block px-4 py-2 text-sm hover:bg-gray-700/50">Plain Text (.txt)</button>
                                    <button onClick={() => handleDownload('md')} className="w-full text-left text-primary block px-4 py-2 text-sm hover:bg-gray-700/50">Markdown (.md)</button>
                                    <button onClick={() => !isDownloadingPdf && handleDownload('pdf')} className={`w-full text-left text-primary block px-4 py-2 text-sm hover:bg-gray-700/50 ${isDownloadingPdf ? 'cursor-not-allowed opacity-50' : ''}`}>
                                        {isDownloadingPdf ? 'Formatting PDF...' : 'Studio Sheet (.pdf)'}
                                    </button>
                                </div>
                            </div>
                        )}
                    </div>
                </div>
              )}
            </div>

            <div className="mt-12">
              <History 
                history={history}
                onLoad={handleLoadHistory}
                onClear={handleClearHistory}
              />
            </div>
          </main>
        );
    }
  };

  return (
    <>
      {showLoadConfirmation && (
        <div className="fixed top-5 left-1/2 -translate-x-1/2 bg-green-600 text-white px-6 py-2 rounded-full shadow-lg z-50 confirmation-animation" role="alert">
          ✅ Song loaded successfully!
        </div>
      )}

      <div id="pdf-content" style={{
            position: 'absolute', left: '-9999px', width: '8.27in', minHeight: '11.69in', padding: '1in',
            backgroundColor: 'white', color: 'black', fontSize: '12pt', lineHeight: '1.6',
      }}>
          <h1 style={{ fontFamily: 'serif', fontSize: '24pt', fontWeight: 'bold', borderBottom: '2px solid black', paddingBottom: '10px', marginBottom: '20px' }}>{songTitle || 'Untitled'}</h1>
          <p style={{fontFamily: 'sans-serif'}}><strong>Artist:</strong> {artistName || 'N/A'}</p>
          <p style={{fontFamily: 'sans-serif'}}><strong>Album:</strong> {albumName || 'N/A'}</p>
          <p style={{fontFamily: 'sans-serif', whiteSpace: 'pre-wrap'}}><strong>Theme:</strong> {theme}</p>
          <br />
          <div style={{ fontFamily: 'serif', whiteSpace: 'pre-wrap', fontSize: '12pt' }}>
              {formatLyricsForPdf(lyrics)}
          </div>
      </div>

      <div className="rasta-stripes"></div>
      <div className="container mx-auto p-4 md:p-8 max-w-3xl min-h-screen">
        <header className="mb-8 relative">
          <div className="absolute top-0 right-0 text-right text-sm z-10">
            <p className="text-secondary">Welcome, <span className="font-bold text-title">{currentUser}</span></p>
            <button onClick={handleLogout} className="text-red-400 hover:underline">Logout</button>
          </div>
          <div className="absolute top-0 left-0 text-left text-sm z-10">
            <ThemeSwitcher onThemeChange={setAppTheme} />
          </div>

          <div className="flex flex-col justify-center items-center pt-8 md:pt-4 text-center">
            <h1 className="title-font text-5xl md:text-6xl font-bold tracking-tight">
              PATOIS Lyricist
            </h1>
            <div className="my-4">
              <HeaderIcon />
            </div>
            <p className="text-accent text-lg font-medium">Crafting Authentic Reggae Riddims</p>
          </div>
           <nav className="flex justify-center gap-4 mt-4 border-b border-primary pb-2">
              <button onClick={() => setCurrentView('main')} className={`px-4 py-1 rounded-md text-sm font-semibold transition-all ${currentView === 'main' ? 'bg-title text-black' : 'hover:bg-gray-700/50'}`}>Generator</button>
              {currentUserRole === 'admin' && (
                <button onClick={() => setCurrentView('admin')} className={`px-4 py-1 rounded-md text-sm font-semibold transition-all ${currentView === 'admin' ? 'bg-title text-black' : 'hover:bg-gray-700/50'}`}>Admin Panel</button>
              )}
              <button onClick={() => setCurrentView('testing')} className={`px-4 py-1 rounded-md text-sm font-semibold transition-all ${currentView === 'testing' ? 'bg-title text-black' : 'hover:bg-gray-700/50'}`}>Diagnostics</button>
            </nav>
        </header>

        {renderView()}

        <footer className="text-center mt-12 text-sm text-secondary pb-8">
          <p>Lyrics generated by AI in Kingston spirit. For inspiration only.</p>
          <p className="mt-1 opacity-75">Powered by Google Gemini 3 Pro</p>
        </footer>
      </div>
    </>
  );
};

export default App;

import React, { useState, useCallback, useEffect, useRef } from 'react';
import { generateLyrics } from './services/geminiService';
