             {authError && <p className="text-red-400 text-center mb-4 bg-red-900/50 p-2 rounded-lg text-sm border border-red-500/30">{authError}</p>}
            <form onSubmit={(e) => { e.preventDefault(); authView === 'login' ? handleLogin() : handleRegister(); }}>
              <div className="form-group">
                <div className="input-wrapper">
                  <input 
                    type="text" 
                    placeholder="Username" 
                    required 
                    value={authUsername} 
                    onChange={(e) => setAuthUsername(e.target.value)} 
                    className="w-full p-4 bg-gray-900 border-2 border-primary rounded-xl focus:outline-none focus:border-[#D4AF37] focus:ring-4 focus:ring-[#D4AF37]/20 transition-all"
