// Web Speech API Types
interface SpeechRecognitionAlternative {
  readonly transcript: string;
  readonly confidence: number;
}
interface SpeechRecognitionResult {
  readonly isFinal: boolean;
  readonly length: number;
  item(index: number): SpeechRecognitionAlternative;
  [index: number]: SpeechRecognitionAlternative;
}
interface SpeechRecognitionResultList {
  readonly length: number;
  item(index: number): SpeechRecognitionResult;
  [index: number]: SpeechRecognitionResult;
}
interface SpeechRecognitionErrorEvent extends Event {
  readonly error: string;
}
interface SpeechRecognitionEvent extends Event {
  readonly resultIndex: number;
  readonly results: SpeechRecognitionResultList;
}
interface SpeechRecognition extends EventTarget {
  continuous: boolean;
  interimResults: boolean;
  lang: string;
  onstart: ((this: SpeechRecognition, ev: Event) => any) | null;
  onend: ((this: SpeechRecognition, ev: Event) => any) | null;
  onerror: ((this: SpeechRecognition, ev: SpeechRecognitionErrorEvent) => any) | null;
  onresult: ((this: SpeechRecognition, ev: SpeechRecognitionEvent) => any) | null;
  start(): void;
  stop(): void;
}
interface SpeechRecognitionStatic {
  new (): SpeechRecognition;
}
declare global {
  interface Window {
    SpeechRecognition: SpeechRecognitionStatic;
    webkitSpeechRecognition: SpeechRecognitionStatic;
  }
}

const App: React.FC = () => {
  // Auth & Session State
  const [currentUser, setCurrentUser] = useState<string | null>(() => localStorage.getItem('patoisLyricistCurrentUser'));
  const [currentUserRole, setCurrentUserRole] = useState<'user' | 'admin'>('user');
  const [authView, setAuthView] = useState<'login' | 'register'>('login');
  const [authUsername, setAuthUsername] = useState('');
  const [authPassword, setAuthPassword] = useState('');
  const [privacyAccepted, setPrivacyAccepted] = useState(false);
  const [authError, setAuthError] = useState<string | null>(null);

  // Security & Privacy State (SOC 2)
  const [failedAttempts, setFailedAttempts] = useState(0);
  const [lockoutUntil, setLockoutUntil] = useState<number | null>(null);
  const [sessionTimeoutReached, setSessionTimeoutReached] = useState(false);
  const [showErasureConfirm, setShowErasureConfirm] = useState(false);

  // App State
  const [theme, setTheme] = useState<string>('');
  const [rhymeScheme, setRhymeScheme] = useState<string>('AABB');
  const [djPersona, setDjPersona] = useState<string>('Hype Man');
  const [songStructure, setSongStructure] = useState<string[]>([
    'Intro', 'Verse', 'Chorus', 'Verse', 'Chorus', 'DJ Toast', 'Outro'
  ]);
  const [songTitle, setSongTitle] = useState<string>('');
  const [artistName, setArtistName] = useState<string>('');
  const [albumName, setAlbumName] = useState<string>('');
  const [lyrics, setLyrics] = useState<string>('');
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [isStructureVisible, setIsStructureVisible] = useState(true);
  const [showLoadConfirmation, setShowLoadConfirmation] = useState<boolean>(false);
  const [currentView, setCurrentView] = useState<View>('main');
  const [isDownloadMenuOpen, setIsDownloadMenuOpen] = useState(false);

  // Voice State
  const [isListening, setIsListening] = useState(false);
  const [isSpeechRecognitionSupported, setIsSpeechRecognitionSupported] = useState(false);
  const recognitionRef = useRef<SpeechRecognition | null>(null);
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  const downloadMenuRef = useRef<HTMLDivElement>(null);
  const [history, setHistory] = useState<HistoryEntry[]>([]);
  const timeoutRef = useRef<number | null>(null);

  // Constants
  const THEME_LIMIT = 3000;
  const MAX_FAILED_ATTEMPTS = 3;
  const LOCKOUT_DURATION = 60 * 1000;
  const INACTIVITY_LIMIT = 15 * 60 * 1000; // 15 minutes

  // Session Timeout Logic (SOC 2)
  const resetInactivityTimer = useCallback(() => {
    if (timeoutRef.current) window.clearTimeout(timeoutRef.current);
    if (currentUser) {
      timeoutRef.current = window.setTimeout(() => {
        handleSessionExpired();
      }, INACTIVITY_LIMIT);
    }
  }, [currentUser]);

  useEffect(() => {
    const events = ['mousedown', 'keydown', 'scroll', 'touchstart'];
    events.forEach(e => window.addEventListener(e, resetInactivityTimer));
    resetInactivityTimer();
    return () => {
      events.forEach(e => window.removeEventListener(e, resetInactivityTimer));
      if (timeoutRef.current) window.clearTimeout(timeoutRef.current);
    };
  }, [resetInactivityTimer]);

  const handleSessionExpired = () => {
    setSessionTimeoutReached(true);
    handleLogout();
  };

  useEffect(() => {
    const loggedInUser = localStorage.getItem('patoisLyricistCurrentUser');
    if (loggedInUser) {
      const users = getUsers();
      if (users[loggedInUser]) {
        setCurrentUser(loggedInUser);
        setCurrentUserRole(users[loggedInUser].role);
        const savedHistory = secureGetItem<HistoryEntry[]>(`patoisLyricistHistory_${loggedInUser}`);
        setHistory(savedHistory || []);
      } else {
        handleLogout();
      }
    }
    const savedTheme = localStorage.getItem('patoisLyricistTheme') as Theme || 'dark';
    setAppTheme(savedTheme);
    const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (SR) setIsSpeechRecognitionSupported(true);
  }, []);

  useEffect(() => {
    if (!currentUser) return;
    secureSetItem(`patoisLyricistHistory_${currentUser}`, history);
  }, [history, currentUser]);

  const setAppTheme = (themeName: Theme) => {
      document.body.setAttribute('data-theme', themeName);
      localStorage.setItem('patoisLyricistTheme', themeName);
  };

  const getUsers = (): Record<string, User> => {
    return secureGetItem<Record<string, User>>('patoisLyricistUsers') || {};
  };

  const handleRegister = () => {
    if (!authUsername.trim() || authPassword.length < 8) {
      setAuthError('Username required and password must be at least 8 characters.');
      return;
    }
    if (!privacyAccepted) {
        setAuthError('You must accept the Privacy Policy to continue.');
        return;
    }
    const users = getUsers();
    if (users[authUsername]) {
      setAuthError('Username already exists.');
      return;
    }
    users[authUsername] = {
        password: authPassword,
        role: authUsername === 'admin' ? 'admin' : 'user',
        privacyAccepted: true
    };
    secureSetItem('patoisLyricistUsers', users);
    logAction('system', 'User Registered', { username: authUsername });
    handleLogin();
  };

  const handleLogin = () => {
    if (lockoutUntil && Date.now() < lockoutUntil) {
        setAuthError(`Too many failed attempts. Try again in ${Math.ceil((lockoutUntil - Date.now()) / 1000)}s.`);
        return;
    }
    const users = getUsers();
    const user = users[authUsername];
    if (user && user.password === authPassword) {
      localStorage.setItem('patoisLyricistCurrentUser', authUsername);
      setCurrentUser(authUsername);
      setCurrentUserRole(user.role);
      setAuthUsername('');
      setAuthPassword('');
      setAuthError(null);
      setFailedAttempts(0);
      const savedHistory = secureGetItem<HistoryEntry[]>(`patoisLyricistHistory_${authUsername}`);
      setHistory(savedHistory || []);
      logAction(authUsername, 'User Login', { success: true });
    } else {
      const newAttempts = failedAttempts + 1;
      setFailedAttempts(newAttempts);
      logAction(authUsername || 'unknown', 'User Login Failed', { attempt: newAttempts });
      if (newAttempts >= MAX_FAILED_ATTEMPTS) {
          setLockoutUntil(Date.now() + LOCKOUT_DURATION);
          setAuthError(`Account locked for 60 seconds.`);
      } else {
          setAuthError(`Invalid credentials. ${MAX_FAILED_ATTEMPTS - newAttempts} attempts left.`);
      }
    }
  };

  const handleLogout = () => {
    if (isListening) recognitionRef.current?.stop();
    logAction(currentUser || 'unknown', 'User Logout', {});
    localStorage.removeItem('patoisLyricistCurrentUser');
    setCurrentUser(null);
    setCurrentUserRole('user');
    setHistory([]);
    setTheme('');
    setLyrics('');
    setError(null);
    setCurrentView('main');
  };

  const handleDeleteAccount = () => {
    if (!currentUser) return;
    const users = getUsers();
    delete users[currentUser];
    secureSetItem('patoisLyricistUsers', users);
    removeItem(`patoisLyricistHistory_${currentUser}`);
    logAction(currentUser, 'User Deleted Own Account', { timestamp: new Date().toISOString() });
    handleLogout();
    setShowErasureConfirm(false);
  };

  const handleGenerate = useCallback(async () => {
    if (!theme.trim()) { setError('Please enter a theme.'); return; }
    if (isLoading) return;
    setIsLoading(true);
    setError(null);
    setLyrics('');
    try {
      const { title: generatedTitle, lyrics: generatedLyrics } = await generateLyrics(theme, rhymeScheme, djPersona, songStructure);
      setLyrics(generatedLyrics);
      setSongTitle(generatedTitle);
      setHistory(prev => [{
        id: Date.now(), theme, songTitle: generatedTitle, artistName, albumName, lyrics: generatedLyrics,
        timestamp: new Date().toISOString(), rhymeScheme, djPersona, songStructure
      }, ...prev].slice(0, 50));
    } catch (err: any) {
      setError(err.message || 'An error occurred.');
      setLyrics('Generation failed.');
    } finally { setIsLoading(false); }
  }, [theme, rhymeScheme, djPersona, songStructure, artistName, albumName, isLoading]);

  const handleToggleListening = useCallback(() => {
    if (isLoading) return;
    if (isListening) { recognitionRef.current?.stop(); return; }
    const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SR) { setError("Speech recognition unsupported."); return; }
    const recognition = new SR();
    recognitionRef.current = recognition;
    recognition.continuous = true;
    recognition.interimResults = true;
    recognition.onstart = () => { setIsListening(true); setError(null); };
    recognition.onend = () => setIsListening(false);
    recognition.onerror = () => setIsListening(false);
    recognition.onresult = (event) => {
      let transcript = '';
      for (let i = event.resultIndex; i < event.results.length; i++) {
        transcript += event.results[i][0].transcript;
      }
      setTheme(prev => {
        const updated = (prev.endsWith(' ') || prev === '' ? prev : prev + ' ') + transcript;
        return updated.substring(0, THEME_LIMIT);
      });
    };
    recognition.start();
  }, [isLoading, isListening]);

  if (!currentUser) {
    return (
      <div className="login-background">
        {sessionTimeoutReached && (
            <div className="fixed top-5 left-1/2 -translate-x-1/2 bg-yellow-600 text-black px-6 py-2 rounded-full shadow-lg z-50 font-bold" role="alert">
                ⚠️ Session expired due to inactivity.
            </div>
        )}
        <div className="login-container">
          <div className="login-header">
            <div className="login-logo">PATOISLyricist</div>
            <div className="login-subtitle">Privacy-First AI Riddim Laboratory</div>
          </div>
          <div className="login-card">
            <h2 className="card-title">{authView === 'login' ? 'Identity Verification' : 'Enroll Entity'}</h2>
             {authError && <p className="text-red-400 text-center mb-4 bg-red-900/50 p-2 rounded-lg text-sm border border-red-500/30">{authError}</p>}
