const App: React.FC = () => {
  // --- Auth & Session (SOC 2 Compliance) ---
  const [currentUser, setCurrentUser] = useState<string | null>(() => localStorage.getItem('patoisLyricistCurrentUser'));
  const [currentUserRole, setCurrentUserRole] = useState<'user' | 'admin'>('user');
