  const handleGenerate = useCallback(async () => {
    if (!theme.trim()) { setError('Enter a theme.'); return; }
    setIsLoading(true); setError(null); setLyrics('');
    try {
      const result = await generateLyrics(theme, rhymeScheme, djPersona, songStructure);
      setLyrics(result.lyrics); setSongTitle(result.title);
      setHistory(prev => [{
        id: Date.now(), theme, songTitle: result.title, artistName, albumName, lyrics: result.lyrics,
        timestamp: new Date().toISOString(), rhymeScheme, djPersona, songStructure
      }, ...prev].slice(0, 50));
    } catch (err: any) {
      setError(err.message);
    } finally { setIsLoading(false); }
  }, [theme, rhymeScheme, djPersona, songStructure, artistName, albumName]);

  // --- Voice Handlers ---
  const handleToggleListening = useCallback(() => {
    if (isListening) { recognitionRef.current?.stop(); return; }
    const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
    const recognition = new SR();
    recognitionRef.current = recognition;
    recognition.continuous = true;
    recognition.onstart = () => setIsListening(true);
    recognition.onend = () => setIsListening(false);
    recognition.onresult = (e: any) => {
      let text = '';
      for (let i = e.resultIndex; i < e.results.length; i++) text += e.results[i][0].transcript;
      setTheme(prev => (prev + ' ' + text).trim().substring(0, THEME_LIMIT));
