            <form onSubmit={e => { e.preventDefault(); authView === 'login' ? handleLogin() : handleRegister(); }}>
              <div className="form-group"><input type="text" placeholder="Username" required value={authUsername} onChange={e => setAuthUsername(e.target.value)} className="w-full p-4 bg-gray-900 border-2 border-primary rounded-xl focus:border-[#D4AF37] focus:ring-4 focus:ring-[#D4AF37]/20 outline-none" /></div>
              <div className="form-group"><input type="password" placeholder="Password" required value={authPassword} onChange={e => setAuthPassword(e.target.value)} className="w-full p-4 bg-gray-900 border-2 border-primary rounded-xl focus:border-[#D4AF37] focus:ring-4 focus:ring-[#D4AF37]/20 outline-none" /></div>
              {authView === 'register' && (
