import { GoogleGenAI, HarmCategory, HarmBlockThreshold } from "@google/genai";

// Ensure API key is available
if (!process.env.API_KEY) {
  throw new Error("API_KEY environment variable is missing.");
}

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Constants for resiliency
const MAX_RETRIES = 3;
const BACKOFF_MS = 1000;

const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export interface GeneratedSong {
  title: string;
  lyrics: string;
}

/**
 * System Instruction for the AI Agent
 */
const SYSTEM_INSTRUCTION = `
You are an expert Jamaican Reggae Songwriter and Culture Specialist. 
Your goal is to craft lyrics that are indistinguishable from those written by Kingston's finest.

CORE RULES:
1. LANGUAGE: Use deep, authentic Jamaican Patois (Patwa). Use correct tense markers: 'a' (pres cont), 'did' (past), 'a go' (future), 'haffi' (must).
2. GRAMMAR: Follow zero copula rules ("Di riddim sweet" instead of "The riddim is sweet"). Use focus marker 'a' for emphasis.
3. SOUL: Include soulful ad-libs (e.g., "(Woooah-oy!)", "(Jah Know!)") and elongated vowels for sustained notes.
4. STRUCTURE: Respect the user-defined song structure exactly. Use [Section Name] labels.
5. DJ TOAST: If a DJ Toast is requested, deliver high-energy, percussive rhythmic speech tailored to the selected persona.
6. TITLE: Provide a unique title in double quotes on the first line.

CONTENT THEMES:
- Spirituality & Rastafari (Zion, Babylon, Jah, Nyabinghi).
- Social Commentary (Ghetto struggles, Unity, Peace).
- Celebration (Nice up di dance, Riddim, Vibes).
- Proverbial Wisdom: Integrate authentic Jamaican proverbs naturally to add "Roots" depth.
  * "Wah eye nuh see, heart nuh leap" (What the eye doesn't see, the heart doesn't grieve over - hidden struggles/sorrows).
  * "Chicken merry, hawk deh near" (Success brings hidden dangers; stay alert during prosperity).
  * "Every mickle mek a muckle" (Small, persistent efforts lead to great results).
  * "Rain a fall but dutty tough" (Times are hard despite outward appearances of relief or prosperity).
  * "One one coco full basket" (Progress comes gradually, step by step).
  * "Mi throw mi corn, but mi nuh call nuh fowl" (I am speaking truths; if they apply to you, take heed - used for indirect social critique).
  * "Trouble nuh set like rain" (Misfortune doesn't give a warning).
`;

/**
 * Builds the user prompt based on specific configuration
 */
const buildUserPrompt = (theme: string, rhymeScheme: string, djPersona: string, songStructure: string[]): string => {
  return `
THEME: ${theme}
RHYME SCHEME: ${rhymeScheme}
DJ PERSONA: ${djPersona}
STRUCTURE: ${songStructure.join(' -> ')}

Task: Write a full Reggae song. Ensure the title is on the first line in quotes. 

CRITICAL: Naturally weave at least one or two of the Jamaican proverbs from your instructions into the verses or bridge. 
The integration should feel organic to the story or message of the song, adding a layer of traditional wisdom and "Roots" authenticity.
`;
};

/**
 * Main generation service
 */
export const generateLyrics = async (
  theme: string, 
  rhymeScheme: string, 
  djPersona: string, 
  songStructure: string[]
): Promise<GeneratedSong> => {

  const userPrompt = buildUserPrompt(theme, rhymeScheme, djPersona, songStructure);

  for (let i = 0; i < MAX_RETRIES; i++) {
    try {
      const response = await ai.models.generateContent({
        model: "gemini-3-pro-preview",
        contents: userPrompt,
        config: {
          systemInstruction: SYSTEM_INSTRUCTION,
          temperature: 0.8,
          topP: 0.95,
          maxOutputTokens: 2048,
          safetySettings: [
            { category: HarmCategory.HARM_CATEGORY_HATE_SPEECH, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
            { category: HarmCategory.HARM_CATEGORY_DANGEROUS_CONTENT, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
          ],
        },
      });

      const text = response.text || "";
      if (text.length < 50) throw new Error("Empty or insufficient response from AI.");

      const lines = text.trim().split('\n');
      const titleMatch = lines[0].match(/"(.*?)"/);
      const title = titleMatch ? titleMatch[1] : "Untitled Riddim";
      const lyrics = titleMatch ? lines.slice(1).join('\n').trim() : text;

      return { title, lyrics };

    } catch (err: any) {
      console.error(`Attempt ${i + 1} failed:`, err.message);
      if (i === MAX_RETRIES - 1) throw err;
      await delay(BACKOFF_MS * Math.pow(2, i));
    }
  }

  throw new Error("Generation failed after maximum retries.");
};

