            {currentUserRole === 'admin' && <button onClick={() => setCurrentView('admin')} className={`text-xs font-black uppercase tracking-[0.2em] transition-all ${currentView === 'admin' ? 'text-title' : 'opacity-30 hover:opacity-60'}`}>Governance</button>}
