3. SOUL: Include soulful ad-libs (e.g., "(Woooah-oy!)", "(Jah Know!)", "(Brrrr-ap!)") and elongated vowels for sustained notes.
4. STRUCTURE: Respect the user-defined song structure exactly. Use [Section Name] labels.
5. DJ TOAST: If a DJ Toast is requested, deliver high-energy, percussive rhythmic speech.
6. TITLE: Provide a unique title in double quotes on the first line.

VOCABULARY & IDIOMS:
- Rastafarian Terms: "I-n-I" (Unity), "Ital" (Pure), "Babylon" (System), "Zion" (Freedom), "Reasoning" (Spiritual Talk).
- Street Slang: "Gwan" (What's up), "Link up" (Meet), "Pickney" (Child), "Shell" (Kill it/Excel).
- Idioms: "Tun up di ting", "Nuff respect", "Hard ears", "Red eye" (Greed).

PROVERBIAL WISDOM:
Naturally weave these proverbs into the lyrics to add "Roots" weight:
- "Wah eye nuh see, heart nuh leap" (Hidden struggles).
- "Chicken merry, hawk deh near" (Stay alert in success).
- "Every mickle mek a muckle" (Persistence).
- "Rain a fall but dutty tough" (Hidden hardships).
- "One one coco full basket" (Patience).
- "Empty barrel mek di most noise" (Foolish talk).
- "If yuh waan good, yuh nose haffi run" (Hard work pays off).
`;

export const generateLyrics = async (
  theme: string, 
  rhymeScheme: string, 
  djPersona: string, 
  songStructure: string[]
): Promise<GeneratedSong> => {

  const prompt = `
THEME: ${theme}
RHYME SCHEME: ${rhymeScheme}
DJ PERSONA: ${djPersona}
STRUCTURE: ${songStructure.join(' -> ')}

Task: Write a full Reggae song. Title in quotes on the first line. 
Incorporate authentic proverbs and deep Patois vocabulary. 
Ensure the rhythm matches the specified structure.
`;

  for (let i = 0; i < MAX_RETRIES; i++) {
    try {
      const response = await ai.models.generateContent({
        model: "gemini-3-pro-preview",
        contents: prompt,
        config: {
          systemInstruction: SYSTEM_INSTRUCTION,
          temperature: 0.8,
          topP: 0.9,
          thinkingConfig: { thinkingBudget: 0 } // Disable explicit thinking to prioritize creative flow and lower latency
        },
      });

      const text = response.text || "";
      const lines = text.trim().split('\n');
      const titleMatch = lines[0].match(/"(.*?)"/);
      const title = titleMatch ? titleMatch[1] : "Untitled Riddim";
      const lyrics = titleMatch ? lines.slice(1).join('\n').trim() : text;

      return { title, lyrics };
    } catch (err: any) {
      if (i === MAX_RETRIES - 1) {
        console.error("Gemini API Error after max retries:", err);
        throw err;
      }
      await delay(BACKOFF_MS * Math.pow(2, i));
    }
  }
  throw new Error("Lyric generation failed after multiple attempts.");
};

import React, { useState } from 'react';
import { GoogleGenAI } from "@google/genai";
import html2canvas from 'html2canvas';

type TestStatus = 'idle' | 'running' | 'success' | 'error';
type ActiveTab = 'self-test' | 'e2e-suite';

interface TestResult {
    name: string;
    status: TestStatus;
    message: string;
}

