import React, { useEffect, useRef } from 'react';

const Equalizer: React.FC = () => {
  const barsRef = useRef<(HTMLDivElement | null)[]>([]);
  const requestRef = useRef<number | null>(null);

  useEffect(() => {
    const animate = () => {
      const now = Date.now();
      barsRef.current.forEach((bar, index) => {
        if (!bar) return;

        // Create a wave pattern across the 32 bars
        // index / 4 creates a slow moving wave
        // now / 300 controls the speed of the wave
        const wave = Math.sin(now / 300 + index / 4) * 0.5 + 0.5;

        // Add some localized "audio" noise for texture
        const noise = Math.random() * 0.2;

        // Scale to percentage
        const heightPercentage = Math.max(8, (wave + noise) * 85 + 5);

        bar.style.height = `${heightPercentage}%`;
      });
      requestRef.current = requestAnimationFrame(animate);
    };

    requestRef.current = requestAnimationFrame(animate);
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, []);

  return (
    <div className="equalizer-container" aria-hidden="true">
      {Array.from({ length: 32 }).map((_, i) => (
        <div
          key={i}
          ref={(el) => (barsRef.current[i] = el)}
          className="equalizer-bar"
          style={{ height: '10%' }}
        />
      ))}
    </div>
  );
};

