import React, { useEffect, useRef } from 'react';

interface EqualizerProps {
  speed?: 'S' | 'M' | 'F';
}

/**
 * Equalizer Component
 * 
 * Animation timing is calculated using the formula:
 * Divisor = 60,000 / (2 * PI * BPM)
 * 
 * Note: All speeds have been reduced by 50% per user request.
 */
const Equalizer: React.FC<EqualizerProps> = ({ speed = 'M' }) => {
  const barsRef = useRef<(HTMLDivElement | null)[]>([]);
  const requestRef = useRef<number | null>(null);

  useEffect(() => {
    const animate = () => {
      const now = Date.now();

      /**
       * BPM Mapping (Post 50% Reduction):
       * S (Slow): 40 BPM (Roots) -> Divisor ~238
       * M (Medium): 57.5 BPM (Riddim) -> Divisor ~166
       * F (Fast/Variable): 70-90 BPM -> Divisor ~136 to ~106
       */
      let divisor = 166; // Default M

      if (speed === 'S') {
        divisor = 238; // Half-speed of 80 BPM
      } else if (speed === 'F') {
        // Fluctuates rhythmically between 70 and 90 BPM (Half-speed of 140-180 BPM)
        const bpmVariance = 80 + Math.sin(now / 1500) * 10;
        divisor = 9549 / bpmVariance;
      }

      barsRef.current.forEach((bar, index) => {
        if (!bar) return;

        // Create a traveling wave pattern across the 32 channels
        const phase = now / divisor + index / 3;
        const wave = Math.sin(phase) * 0.5 + 0.5;

        // Add transient "audio spikes" (percussive noise)
        const transients = Math.random() * 0.12;

        // Apply secondary modulation to simulate complex riddim layers
        const subMod = Math.sin(phase * 0.5) * 0.1;

        // Scale to final percentage (Min 8%, Max 95%)
        const heightPercentage = Math.max(8, (wave + transients + subMod) * 82 + 5);

        bar.style.height = `${heightPercentage}%`;
      });
      requestRef.current = requestAnimationFrame(animate);
    };

    requestRef.current = requestAnimationFrame(animate);
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [speed]);

  return (
    <div className="equalizer-container" aria-hidden="true" style={{ display: 'flex', alignItems: 'flex-end' }}>
      {Array.from({ length: 32 }).map((_, i) => (
        <div
          key={i}
          // Fix: Wrap assignment in a block to ensure the ref callback returns void, 
          // avoiding the TypeScript error where it implicitly returns the HTMLDivElement.
          ref={(el) => { barsRef.current[i] = el; }}
          className="equalizer-bar"
          style={{ height: '10%' }}
        />
      ))}
    </div>
  );
};

export default Equalizer;

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const MAX_RETRIES = 3;
const BACKOFF_MS = 1000;

const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

export interface GeneratedSong {
  title: string;
  lyrics: string;
}

const SYSTEM_INSTRUCTION = `
You are an expert Jamaican Reggae Songwriter and Culture Specialist. 
Your goal is to craft lyrics that are indistinguishable from those written by Kingston's finest artists.

CORE RULES:
1. LANGUAGE: Use deep, authentic Jamaican Patois (Patwa). Use correct tense markers: 'a' (pres cont), 'did' (past), 'a go' (future), 'haffi' (must).
2. GRAMMAR: Follow zero copula rules ("Di riddim sweet" instead of "The riddim is sweet"). Use focus marker 'a' for emphasis.
3. SOUL: Include soulful ad-libs (e.g., "(Woooah-oy!)", "(Jah Know!)", "(Brrrr-ap!)") and elongated vowels for sustained notes.
4. STRUCTURE: Respect the user-defined song structure exactly. Use [Section Name] labels.
5. DJ TOAST: If a DJ Toast is requested, deliver high-energy, percussive rhythmic speech.
6. TITLE: Provide a unique title in double quotes on the first line.

SPECIFIC PATOIS GRAMMAR REFINEMENTS:

- PLURALIZATION (The 'dem' Marker): 
  In Patois, nouns are not pluralized with '-s'. Instead, the plural marker 'dem' is placed immediately after the noun, typically when referring to a specific group already introduced or preceded by the definite article 'di'.
    - Collective Groups: "Di ghetto youth dem a rise" (The youths from the ghetto are rising).
    - Objects of Resistance: "Bun di fire pon di Babylon system dem" (Burn the fire on the oppressive systems).
    - Musical Elements: "When di drum dem lick, wi feel it" (When the drums strike, we feel it).
    - People Groups: "Di soundboy dem haffi run" (The sound system operators must flee).
    - Associative Plural: Using 'dem' after a proper name refers to that person and their group. Example: "Ziggy dem deh bout" (Ziggy and his crew are around).

- PRONOUNS (The Versatility of 'Wi'):
  The pronoun 'wi' is exceptionally versatile in Patois, serving as the subject (we), the object (us), and often as a possessive (our), especially in roots reggae contexts emphasizing collective identity.
    - Subject (We): "Wi a go trot through di valley" (We are going to travel through the valley).
    - Object (Us): "Father Jah, guide wi and protect wi" (Father Jah, guide us and protect us).
    - Possessive (Our): "Wi culture strong, unnu cyaa touch it" (Our culture is strong, you all cannot touch it).
    - Reflexive Hint: Sometimes 'wi' is paired with 'self' for emphasis: "Wi haffi love wi-self" (We must love ourselves).

VOCABULARY & IDIOMS:
- Rastafarian Terms: "I-n-I" (Unity/Divine Connection), "Ital" (Pure/Natural), "Babylon" (Oppressive System), "Zion" (Spiritual Home/Freedom), "Reasoning" (Spiritual Talk).
- Street Slang: "Gwan" (What's up/Go on), "Link up" (Meet/Connect), "Pickney" (Child), "Shell" (Kill it/Excel), "Likkle more" (See you later).
- Idioms & Phrases:
    - "Tun up di ting": Increase the intensity or quality of something.
    - "Nuff respect": A term of high regard or acknowledgement.
    - "Hard ears": Stubborn or refusing to listen to advice.
    - "Red eye": Greed or intense envy.
    - "Small up yuhself": To make room for others, physically or socially.
    - "Walk good": A parting blessing wishing someone safety and prosperity.
    - "Soon come": An expression of coming eventually, emphasizing patience over precise timing.
    - "Tan teddy": To stay still, remain calm, or keep a steady course.
    - "Feel no way": Don't worry about it, take no offense, or be at peace with a situation.
    - "Talk and taste your tongue": Think carefully before you speak; avoid reckless words.

PROVERBIAL WISDOM:
Naturally weave these proverbs into the lyrics to add "Roots" weight and spiritual depth:
- "Wah eye nuh see, heart nuh leap" (What the eye doesn't see, the heart doesn't grieve over).
- "Chicken merry, hawk deh near" (Be cautious in times of ease; danger can lurk in success).
- "Every mickle mek a muckle" (Small things add up; persistence leads to greatness).
- "Rain a fall but dutty tough" (Life may seem fine on the surface, but times are hard underneath).
- "One one coco full basket" (Patience and steady progress fill the container).
- "Empty barrel mek di most noise" (People who know the least often talk the loudest).
- "If yuh waan good, yuh nose haffi run" (Success requires hard work and sacrifice).
- "No hang yuh hat higher than yuh can reach" (Live within your means; maintain humility).
- "Trouble nuh set like rain" (Disaster strikes without warning).
- "When cocoa ripe, it mus' bus'" (Success or truth will eventually reveal itself).
- "Likkle but wi tallawah" (Small but strong and fearless).
- "Better fi shadow leh yuh than fi let yuh substance go" (Character and integrity are more important than reputation).
- "Duppy know who fi frighten" (Bullies target those they perceive as weak).
`;

export const generateLyrics = async (
  theme: string, 
  rhymeScheme: string, 
  djPersona: string, 
  songStructure: string[],
  songDescription: string = ""
): Promise<GeneratedSong> => {

  const prompt = `
THEME: ${theme}
DESCRIPTION/INSTRUCTIONS: ${songDescription}
RHYME SCHEME: ${rhymeScheme}
DJ PERSONA: ${djPersona}
STRUCTURE: ${songStructure.join(' -> ')}

Task: Write a full Reggae song. Title in quotes on the first line. 
Incorporate authentic proverbs, refined grammar (especially the 'dem' plural marker and 'wi' pronoun), and deep Patois vocabulary and idioms as outlined in your instructions. 
The proverbs, idioms, and specific grammatical structures should be woven naturally into the verses or chorus to provide moral weight, social commentary, or "Roots" authenticity. 
Ensure the rhythm and flow match the specified structure and follow the provided description if available.
`;

  for (let i = 0; i < MAX_RETRIES; i++) {
    try {
      const response = await ai.models.generateContent({
        model: "gemini-3-pro-preview",
        contents: prompt,
        config: {
          systemInstruction: SYSTEM_INSTRUCTION,
          temperature: 0.8,
          topP: 0.9,
          thinkingConfig: { thinkingBudget: 4000 } 
        },
      });

      const text = response.text || "";
      const lines = text.trim().split('\n');
      const titleMatch = lines[0].match(/"(.*?)"/);
      const title = titleMatch ? titleMatch[1] : "Untitled Riddim";
      const lyrics = titleMatch ? lines.slice(1).join('\n').trim() : text;

      return { title, lyrics };
    } catch (err: any) {
      if (i === MAX_RETRIES - 1) {
        console.error("Gemini API Error after max retries:", err);
        throw err;
      }
      await delay(BACKOFF_MS * Math.pow(2, i));
    }
  }
  throw new Error("Lyric generation failed after multiple attempts.");
};

