                <textarea id="songDescription" value={songDescription} onChange={e => setSongDescription(e.target.value)} maxLength={DESC_LIMIT} placeholder="Specific instructions (vibes, mood, story details)..." className="w-full p-6 bg-black/40 border-2 border-white/5 rounded-3xl focus:border-title focus:ring-4 focus:ring-title/5 outline-none transition-all h-32 text-base placeholder:opacity-30" />
